 11→/// In-memory implementation of [`CrmStore`] for testing.
 12→#[derive(Debug, Default)]
 13→pub struct MemoryCrmStore {
 14→    contacts: RwLock<HashMap<String, Contact>>,
 15→    channels: RwLock<HashMap<String, ContactChannel>>,
 16→    matters: RwLock<HashMap<String, Matter>>,
 17→    interactions: RwLock<HashMap<String, Interaction>>,
 18→}
