 20→impl MemoryCrmStore {
 21→    #[must_use]
 22→    pub fn new() -> Self {
 23→        Self::default()
 24→    }
 25→}
 26→
 27→#[async_trait]
 28→impl CrmStore for MemoryCrmStore {
 29→    // ── Contacts ──────────────────────────────────────────────────────────────
 30→
 31→    async fn list(&self) -> Result<Vec<Contact>> {
 32→        let contacts = self.contacts.read().unwrap_or_else(|e| e.into_inner());
 33→        let mut out: Vec<Contact> = contacts.values().cloned().collect();
 34→        out.sort_by_key(|c| std::cmp::Reverse(c.updated_at));
 35→        Ok(out)
 36→    }
 37→
 38→    async fn get(&self, id: &str) -> Result<Option<Contact>> {
 39→        let contacts = self.contacts.read().unwrap_or_else(|e| e.into_inner());
 40→        Ok(contacts.get(id).cloned())
 41→    }
 42→
 43→    async fn get_by_external(&self, source: &str, external_id: &str) -> Result<Option<Contact>> {
 44→        let contacts = self.contacts.read().unwrap_or_else(|e| e.into_inner());
 45→        Ok(contacts
 46→            .values()
 47→            .find(|c| {
 48→                c.source.as_deref() == Some(source) && c.external_id.as_deref() == Some(external_id)
 49→            })
 50→            .cloned())
 51→    }
 52→
 53→    async fn upsert(&self, contact: Contact) -> Result<()> {
 54→        let mut contacts = self.contacts.write().unwrap_or_else(|e| e.into_inner());
 55→        contacts.insert(contact.id.clone(), contact);
 56→        Ok(())
 57→    }
 58→
 59→    async fn delete(&self, id: &str) -> Result<()> {
 60→        let mut contacts = self.contacts.write().unwrap_or_else(|e| e.into_inner());
 61→        contacts.remove(id);
 62→        Ok(())
 63→    }
